const String indexHTML = F("<!DOCTYPE html>\n<html lang=\"en\">\n\n<head>\n <meta charset=\"UTF-8\">\n <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0, maximum-scale=1.0, user-scalable=no\">\n <title>RC Car Control</title>\n <style>\n :root {\n --panel: rgba(22, 28, 35, 0.92);\n --line: rgba(255, 255, 255, 0.12);\n --text: #f5f8fb;\n --muted: #9fadba;\n --green: #35d07f;\n --red: #ff555f;\n --blue: #3f8cff;\n }\n\n * {\n box-sizing: border-box;\n -webkit-tap-highlight-color: transparent;\n }\n\n html,\n body {\n width: 100%;\n height: 100%;\n margin: 0;\n overflow: hidden;\n color: var(--text);\n font-family: Arial, Helvetica, sans-serif;\n background: linear-gradient(135deg, #0f151b 0%, #18212b 55%, #101418 100%);\n touch-action: none;\n user-select: none;\n }\n\n .chooser,\n .rotate-message {\n position: fixed;\n inset: 0;\n z-index: 20;\n display: none;\n place-items: center;\n padding: 24px;\n text-align: center;\n background: #101418;\n }\n\n .chooser.show,\n .rotate-message.show {\n display: grid;\n }\n\n .chooser-box,\n .rotate-box {\n width: min(520px, 100%);\n display: grid;\n gap: 14px;\n padding: 18px;\n border: 1px solid var(--line);\n border-radius: 8px;\n background: var(--panel);\n }\n\n .chooser-box h2,\n .rotate-box strong {\n margin: 0;\n font-size: 24px;\n letter-spacing: 0;\n }\n\n .chooser-box p,\n .rotate-box span {\n color: var(--muted);\n }\n\n .choice-grid {\n display: grid;\n grid-template-columns: 1fr 1fr;\n gap: 10px;\n }\n\n .choice-grid button {\n height: auto;\n min-height: 92px;\n padding: 12px;\n border: 1px solid var(--line);\n border-radius: 8px;\n color: var(--text);\n text-align: left;\n background: #202d38;\n font: inherit;\n font-weight: 700;\n }\n\n .choice-grid strong {\n display: block;\n margin-bottom: 6px;\n font-size: 18px;\n }\n\n .choice-grid span {\n display: block;\n color: var(--muted);\n font-size: 13px;\n font-weight: 400;\n line-height: 1.35;\n }\n\n .controller-shell {\n width: 100vw;\n height: 100dvh;\n }\n\n .split-layout,\n .round-layout {\n width: 100%;\n height: 100%;\n display: none;\n }\n\n .split-layout.active,\n .round-layout.active {\n display: grid;\n }\n\n .split-layout {\n min-height: 340px;\n padding: 10px;\n grid-template-columns: 1fr;\n grid-template-rows: auto auto auto auto;\n gap: 10px;\n }\n\n .topbar {\n grid-column: 1 / -1;\n min-height: 58px;\n display: grid;\n grid-template-columns: 1fr;\n grid-template-areas:\n \"title\"\n \"connection\"\n \"fullscreen\"\n \"status\";\n gap: 10px;\n align-items: center;\n padding: 8px 10px;\n border: 1px solid var(--line);\n border-radius: 8px;\n background: var(--panel);\n box-shadow: 0 14px 34px rgba(0, 0, 0, 0.28);\n }\n\n h1 {\n margin: 0;\n font-size: clamp(18px, 2.8vw, 28px);\n letter-spacing: 0;\n white-space: nowrap;\n grid-area: title;\n }\n\n .connection {\n display: grid;\n grid-area: connection;\n grid-template-columns: minmax(0, 1fr) 58px 72px 72px;\n gap: 8px;\n align-items: center;\n }\n\n input,\n button,\n select {\n height: 38px;\n border-radius: 8px;\n border: 1px solid var(--line);\n font: inherit;\n }\n\n input,\n select {\n min-width: 0;\n padding: 0 10px;\n color: var(--text);\n background: #0f171f;\n }\n\n button {\n color: var(--text);\n background: #25303a;\n font-weight: 700;\n }\n\n button:disabled {\n opacity: 0.45;\n }\n\n .connect {\n color: #051108;\n background: var(--green);\n border: 0;\n }\n\n .disconnect {\n background: var(--red);\n border: 0;\n }\n\n .fullscreen {\n min-width: 92px;\n background: #2d3945;\n grid-area: fullscreen;\n width: 100%;\n }\n\n .status {\n color: var(--muted);\n text-align: left;\n font-size: 12px;\n grid-area: status;\n }\n\n .status strong {\n display: block;\n color: var(--red);\n font-size: 15px;\n }\n\n .status.connected strong {\n color: var(--green);\n }\n\n .pad-panel,\n .middle-panel,\n .round-main,\n .round-side {\n min-height: 0;\n border: 1px solid var(--line);\n border-radius: 8px;\n background: var(--panel);\n box-shadow: 0 16px 42px rgba(0, 0, 0, 0.3);\n }\n\n .pad-panel {\n padding: 10px;\n display: grid;\n grid-template-rows: auto 1fr;\n gap: 8px;\n align-items: center;\n }\n\n .pad-title,\n .module-title {\n margin: 0;\n color: var(--muted);\n font-size: 12px;\n font-weight: 700;\n text-align: center;\n text-transform: uppercase;\n }\n\n .dpad {\n width: min(72vw, 280px);\n height: min(72vw, 280px);\n min-width: 180px;\n min-height: 180px;\n max-width: calc(100dvh - 110px);\n max-height: calc(100dvh - 110px);\n margin: auto;\n display: grid;\n grid-template-columns: 1fr 1fr 1fr;\n grid-template-rows: 1fr 1fr 1fr;\n gap: 8px;\n }\n\n .dpad.vertical .up {\n grid-column: 2;\n grid-row: 1;\n }\n\n .dpad.vertical .down {\n grid-column: 2;\n grid-row: 3;\n }\n\n .dpad.horizontal .left {\n grid-column: 1;\n grid-row: 2;\n }\n\n .dpad.horizontal .right {\n grid-column: 3;\n grid-row: 2;\n }\n\n .dpad-center {\n grid-column: 2;\n grid-row: 2;\n border-radius: 50%;\n border: 1px solid rgba(255, 255, 255, 0.12);\n background: radial-gradient(circle, rgba(255, 255, 255, 0.14), rgba(255, 255, 255, 0.04));\n box-shadow: inset 0 0 20px rgba(0, 0, 0, 0.25);\n }\n\n .pad-button {\n width: 100%;\n height: 100%;\n min-width: 0;\n min-height: 0;\n display: grid;\n place-items: center;\n padding: 0;\n border: 0;\n border-radius: 8px;\n background: linear-gradient(180deg, #33404c, #202a34);\n box-shadow: inset 0 1px 0 rgba(255, 255, 255, 0.16), 0 10px 20px rgba(0, 0, 0, 0.28);\n overflow: hidden;\n }\n\n .arrow-shape {\n display: block;\n width: 44%;\n aspect-ratio: 1;\n color: #f5f8fb;\n background: currentColor;\n clip-path: polygon(50% 6%, 92% 48%, 68% 48%, 68% 94%, 32% 94%, 32% 48%, 8% 48%);\n }\n\n .arrow-down {\n transform: rotate(180deg);\n }\n\n .arrow-left,\n .arrow-right {\n transform: rotate(-90deg);\n }\n\n .arrow-left {\n transform: rotate(-90deg);\n }\n\n .arrow-right {\n transform: rotate(90deg);\n }\n\n .pad-button.active {\n background: linear-gradient(180deg, #66a5ff, #2367d8);\n transform: translateY(2px);\n box-shadow: inset 0 2px 8px rgba(0, 0, 0, 0.28), 0 6px 12px rgba(0, 0, 0, 0.24);\n }\n\n .middle-panel {\n padding: 10px;\n display: grid;\n grid-template-rows: 1fr 1fr;\n gap: 10px;\n }\n\n .module {\n display: grid;\n gap: 8px;\n align-content: center;\n padding: 10px;\n border-radius: 8px;\n background: rgba(10, 16, 22, 0.55);\n }\n\n .slider-row {\n display: grid;\n grid-template-columns: 1fr 48px;\n gap: 8px;\n align-items: center;\n }\n\n input[type=\"range\"] {\n height: 34px;\n padding: 0;\n border: 0;\n background: transparent;\n accent-color: var(--blue);\n }\n\n .value {\n font-weight: 700;\n text-align: right;\n }\n\n .round-layout {\n padding: 10px;\n grid-template-columns: 1fr;\n grid-template-rows: auto minmax(0, 1fr) auto;\n gap: 10px;\n }\n\n .round-layout .topbar {\n min-height: 64px;\n }\n\n .round-main {\n display: grid;\n place-items: center;\n padding: 12px;\n }\n\n .round-side {\n padding: 10px;\n display: grid;\n grid-template-columns: 1fr;\n align-content: start;\n gap: 12px;\n }\n\n .round-pad {\n width: min(78vw, 360px);\n height: min(78vw, 360px);\n min-width: 220px;\n min-height: 220px;\n border-radius: 50%;\n border: 2px solid rgba(255, 255, 255, 0.12);\n position: relative;\n background: radial-gradient(circle at 30% 30%, rgba(255, 255, 255, 0.06), rgba(255, 255, 255, 0.02));\n box-shadow: inset 0 0 30px rgba(0, 0, 0, 0.25);\n }\n\n .stick {\n width: 34%;\n height: 34%;\n min-width: 82px;\n min-height: 82px;\n border-radius: 50%;\n position: absolute;\n top: 50%;\n left: 50%;\n transform: translate(-50%, -50%);\n background: linear-gradient(180deg, #4f99ff, #2b6fd8);\n box-shadow: 0 12px 24px rgba(0, 0, 0, 0.3);\n cursor: grab;\n }\n\n .stick.active {\n cursor: grabbing;\n }\n\n .hidden {\n display: none;\n }\n\n @media (max-width: 760px) {\n .choice-grid {\n grid-template-columns: 1fr;\n }\n }\n\n @media (orientation: landscape) {\n body.controller-picked.round-mode .rotate-message.show {\n display: grid;\n }\n }\n\n @media (orientation: portrait) {\n body.controller-picked.split-mode .rotate-message.show {\n display: grid;\n }\n }\n\n @media (orientation: landscape) and (min-width: 700px) {\n .split-layout {\n min-height: 300px;\n grid-template-columns: 1fr minmax(230px, 0.82fr) 1fr;\n grid-template-rows: auto 1fr;\n gap: 8px;\n }\n\n .topbar {\n grid-template-columns: 1fr auto auto auto;\n grid-template-areas: \"title connection fullscreen status\";\n min-height: 52px;\n padding: 6px 8px;\n }\n\n .connection {\n grid-template-columns: 120px 48px 66px 66px;\n }\n\n .status {\n text-align: right;\n }\n\n .fullscreen {\n min-width: 92px;\n width: auto;\n }\n\n .dpad {\n width: min(38vw, 286px);\n height: min(38vw, 286px);\n min-width: 190px;\n min-height: 190px;\n max-width: calc(100dvh - 105px);\n max-height: calc(100dvh - 105px);\n }\n }\n\n @media (orientation: portrait) and (min-width: 700px) {\n .round-layout {\n padding: 14px;\n gap: 12px;\n }\n\n .round-side {\n grid-template-columns: 1fr 1fr;\n }\n\n .round-pad {\n width: min(72vmin, 380px);\n height: min(72vmin, 380px);\n min-width: 250px;\n min-height: 250px;\n }\n }\n\n @media (max-height: 430px) {\n .split-layout {\n min-height: 300px;\n gap: 8px;\n }\n\n .topbar {\n min-height: 52px;\n padding: 6px 8px;\n }\n\n .connection {\n grid-template-columns: 120px 48px 66px 66px;\n }\n\n input,\n button,\n select {\n height: 34px;\n font-size: 13px;\n }\n\n .module,\n .pad-panel,\n .round-side {\n padding: 8px;\n }\n }\n </style>\n</head>\n\n<body>\n <div class=\"chooser show\" id=\"chooser\">\n <div class=\"chooser-box\">\n <h2>Select Controller</h2>\n <p>Choose one joystick style before starting control.</p>\n <div class=\"choice-grid\">\n <button data-controller=\"round\">\n <strong>Round Joystick</strong>\n <span>Portrait mode with one floating stick.</span>\n </button>\n <button data-controller=\"split\">\n <strong>Split D-pad</strong>\n <span>The same bridge-course style controller in landscape.</span>\n </button>\n </div>\n </div>\n </div>\n\n <div class=\"rotate-message\" id=\"rotateMessage\">\n <div class=\"rotate-box\">\n <strong id=\"rotateTitle\">Rotate Phone</strong>\n <span id=\"rotateText\">Use the correct orientation for this controller.</span>\n </div>\n </div>\n\n <div class=\"controller-shell\">\n <main class=\"split-layout\" id=\"splitLayout\">\n <header class=\"topbar\">\n <h1>RC Car Control</h1>\n <div class=\"connection\">\n <input type=\"text\" id=\"splitIpInput\" value=\"192.168.4.1\" aria-label=\"IP address\">\n <input type=\"text\" id=\"splitPortInput\" value=\"81\" aria-label=\"Port\">\n <button class=\"connect\" id=\"splitStartButton\">Start</button>\n <button class=\"disconnect\" id=\"splitStopButton\" disabled>Stop</button>\n </div>\n <button class=\"fullscreen\" id=\"fullscreenButton\">Full Screen</button>\n <div class=\"status\" id=\"splitStatusBox\">\n <strong id=\"splitStatus\">Disconnected</strong>\n WebSocket 81\n </div>\n </header>\n\n <section class=\"pad-panel\">\n <p class=\"pad-title\">Drive</p>\n <div class=\"dpad vertical\">\n <button class=\"pad-button up\" data-axis=\"y\" data-value=\"-100\" aria-label=\"Front\"><span class=\"arrow-shape arrow-up\"></span></button>\n <div class=\"dpad-center\"></div>\n <button class=\"pad-button down\" data-axis=\"y\" data-value=\"100\" aria-label=\"Back\"><span class=\"arrow-shape arrow-down\"></span></button>\n </div>\n </section>\n\n <section class=\"middle-panel\">\n <div class=\"module\">\n <p class=\"module-title\">Controller</p>\n <select id=\"controllerSelect\">\n <option value=\"round\">Round Joystick</option>\n <option value=\"split\">Split D-pad</option>\n </select>\n </div>\n <div class=\"module\">\n <p class=\"module-title\">Speed</p>\n <div class=\"slider-row\">\n <input type=\"range\" id=\"splitSpeedRange\" min=\"20\" max=\"100\" value=\"100\">\n <span class=\"value\" id=\"splitSpeedValue\">100%</span>\n </div>\n </div>\n </section>\n\n <section class=\"pad-panel\">\n <p class=\"pad-title\">Steer</p>\n <div class=\"dpad horizontal\">\n <button class=\"pad-button left\" data-axis=\"x\" data-value=\"-100\" aria-label=\"Left\"><span class=\"arrow-shape arrow-left\"></span></button>\n <div class=\"dpad-center\"></div>\n <button class=\"pad-button right\" data-axis=\"x\" data-value=\"100\" aria-label=\"Right\"><span class=\"arrow-shape arrow-right\"></span></button>\n </div>\n </section>\n </main>\n\n <main class=\"round-layout\" id=\"roundLayout\">\n <header class=\"topbar\">\n <h1>RC Car Control</h1>\n <div class=\"connection\">\n <input type=\"text\" id=\"roundIpInput\" value=\"192.168.4.1\" aria-label=\"IP address\">\n <input type=\"text\" id=\"roundPortInput\" value=\"81\" aria-label=\"Port\">\n <button class=\"connect\" id=\"roundStartButton\">Start</button>\n <button class=\"disconnect\" id=\"roundStopButton\" disabled>Stop</button>\n </div>\n <div></div>\n <div class=\"status\" id=\"roundStatusBox\">\n <strong id=\"roundStatus\">Disconnected</strong>\n WebSocket 81\n </div>\n </header>\n\n <section class=\"round-main\">\n <div class=\"round-pad\" id=\"roundController\">\n <div class=\"stick\" id=\"joystick\"></div>\n </div>\n </section>\n\n <aside class=\"round-side\">\n <div class=\"module\">\n <p class=\"module-title\">Controller</p>\n <select id=\"roundControllerSelect\">\n <option value=\"round\">Round Joystick</option>\n <option value=\"split\">Split D-pad</option>\n </select>\n </div>\n <div class=\"module\">\n <p class=\"module-title\">Speed</p>\n <div class=\"slider-row\">\n <input type=\"range\" id=\"roundSpeedRange\" min=\"20\" max=\"100\" value=\"100\">\n <span class=\"value\" id=\"roundSpeedValue\">100%</span>\n </div>\n </div>\n </aside>\n </main>\n </div>\n\n <script>\n const JOYSTICK_PACKET = 0;\n const driveState = { type: JOYSTICK_PACKET, x: 0, y: 0, speed: 100 };\n\n let ws;\n let sendInterval;\n let selectedController = '';\n let activePointerId = null;\n\n const chooser = document.getElementById('chooser');\n const rotateMessage = document.getElementById('rotateMessage');\n const rotateTitle = document.getElementById('rotateTitle');\n const rotateText = document.getElementById('rotateText');\n const splitLayout = document.getElementById('splitLayout');\n const roundLayout = document.getElementById('roundLayout');\n const roundPad = document.getElementById('roundController');\n const joystick = document.getElementById('joystick');\n const fullscreenButton = document.getElementById('fullscreenButton');\n\n const splitUi = {\n ip: document.getElementById('splitIpInput'),\n port: document.getElementById('splitPortInput'),\n start: document.getElementById('splitStartButton'),\n stop: document.getElementById('splitStopButton'),\n status: document.getElementById('splitStatus'),\n statusBox: document.getElementById('splitStatusBox'),\n speed: document.getElementById('splitSpeedRange'),\n speedValue: document.getElementById('splitSpeedValue'),\n controller: document.getElementById('controllerSelect')\n };\n\n const roundUi = {\n ip: document.getElementById('roundIpInput'),\n port: document.getElementById('roundPortInput'),\n start: document.getElementById('roundStartButton'),\n stop: document.getElementById('roundStopButton'),\n status: document.getElementById('roundStatus'),\n statusBox: document.getElementById('roundStatusBox'),\n speed: document.getElementById('roundSpeedRange'),\n speedValue: document.getElementById('roundSpeedValue'),\n controller: document.getElementById('roundControllerSelect')\n };\n\n function activeUi() {\n return selectedController === 'split' ? splitUi : roundUi;\n }\n\n function isConnected() {\n return ws && ws.readyState === WebSocket.OPEN;\n }\n\n function setConnected(connected) {\n [splitUi, roundUi].forEach((ui) => {\n ui.status.textContent = connected ? 'Connected' : 'Disconnected';\n ui.statusBox.classList.toggle('connected', connected);\n ui.start.disabled = connected;\n ui.stop.disabled = !connected;\n ui.ip.disabled = connected;\n ui.port.disabled = connected;\n ui.controller.disabled = connected;\n });\n }\n\n function syncSharedFields(sourceUi) {\n const ip = sourceUi.ip.value.trim();\n const port = sourceUi.port.value.trim();\n splitUi.ip.value = ip;\n roundUi.ip.value = ip;\n splitUi.port.value = port;\n roundUi.port.value = port;\n }\n\n function syncSpeed(value) {\n driveState.speed = Number(value);\n splitUi.speed.value = driveState.speed;\n roundUi.speed.value = driveState.speed;\n splitUi.speedValue.textContent = `${driveState.speed}%`;\n roundUi.speedValue.textContent = `${driveState.speed}%`;\n sendState();\n }\n\n function updateOrientationGate() {\n const wrongSplit = selectedController === 'split' && window.matchMedia('(orientation: portrait)').matches;\n const wrongRound = selectedController === 'round' && window.matchMedia('(orientation: landscape)').matches;\n const showGate = document.body.classList.contains('controller-picked') && (wrongSplit || wrongRound);\n\n rotateTitle.textContent = selectedController === 'round' ? 'Rotate Phone Upright' : 'Rotate Phone';\n rotateText.textContent = selectedController === 'round'\n ? 'Use portrait mode for the round joystick.'\n : 'Use landscape mode for the D-pad controller.';\n rotateMessage.classList.toggle('show', showGate);\n }\n\n function setController(controller) {\n selectedController = controller;\n document.body.classList.toggle('round-mode', controller === 'round');\n document.body.classList.toggle('split-mode', controller === 'split');\n splitLayout.classList.toggle('active', controller === 'split');\n roundLayout.classList.toggle('active', controller === 'round');\n splitUi.controller.value = controller;\n roundUi.controller.value = controller;\n stopMotion();\n updateOrientationGate();\n }\n\n function sendState() {\n if (isConnected()) {\n ws.send(JSON.stringify(driveState));\n }\n }\n\n function stopMotion() {\n driveState.x = 0;\n driveState.y = 0;\n joystick.style.left = '50%';\n joystick.style.top = '50%';\n joystick.classList.remove('active');\n document.querySelectorAll('.pad-button.active').forEach((button) => button.classList.remove('active'));\n sendState();\n }\n\n function stopConnection() {\n if (isConnected()) {\n stopMotion();\n ws.close();\n }\n clearInterval(sendInterval);\n setConnected(false);\n stopMotion();\n }\n\n function startConnection(ui) {\n syncSharedFields(ui);\n const ip = ui.ip.value.trim();\n const port = ui.port.value.trim();\n if (!ip || !port) {\n alert('Please enter both IP address and port.');\n return;\n }\n\n ws = new WebSocket(`ws://${ip}:${port}/ws`);\n ws.onopen = () => {\n setConnected(true);\n sendState();\n sendInterval = setInterval(sendState, 80);\n };\n ws.onerror = () => {\n activeUi().status.textContent = 'Connection Error';\n stopConnection();\n };\n ws.onclose = stopConnection;\n }\n\n function bindPadButton(button) {\n const axis = button.dataset.axis;\n const value = Number(button.dataset.value);\n let pointerId = null;\n\n button.addEventListener('pointerdown', (event) => {\n if (!isConnected() || selectedController !== 'split') return;\n event.preventDefault();\n pointerId = event.pointerId;\n button.setPointerCapture(pointerId);\n driveState[axis] = value;\n button.classList.add('active');\n sendState();\n });\n\n button.addEventListener('pointerup', (event) => {\n if (event.pointerId === pointerId) {\n pointerId = null;\n driveState[axis] = 0;\n button.classList.remove('active');\n sendState();\n }\n });\n\n button.addEventListener('pointercancel', () => {\n pointerId = null;\n driveState[axis] = 0;\n button.classList.remove('active');\n sendState();\n });\n }\n\n function updateJoystickPosition(clientX, clientY) {\n const rect = roundPad.getBoundingClientRect();\n const centerX = rect.width / 2;\n const centerY = rect.height / 2;\n const maxDistance = rect.width / 2 - (joystick.offsetWidth / 2);\n let x = clientX - rect.left - centerX;\n let y = clientY - rect.top - centerY;\n const distance = Math.sqrt(x * x + y * y);\n\n if (distance > maxDistance) {\n const angle = Math.atan2(y, x);\n x = maxDistance * Math.cos(angle);\n y = maxDistance * Math.sin(angle);\n }\n\n joystick.style.left = `${centerX + x}px`;\n joystick.style.top = `${centerY + y}px`;\n driveState.x = Math.round((x / maxDistance) * 100);\n driveState.y = Math.round((y / maxDistance) * 100);\n sendState();\n }\n\n joystick.addEventListener('pointerdown', (event) => {\n if (!isConnected() || selectedController !== 'round') return;\n event.preventDefault();\n activePointerId = event.pointerId;\n joystick.setPointerCapture(activePointerId);\n joystick.classList.add('active');\n updateJoystickPosition(event.clientX, event.clientY);\n });\n\n joystick.addEventListener('pointermove', (event) => {\n if (event.pointerId === activePointerId) {\n event.preventDefault();\n updateJoystickPosition(event.clientX, event.clientY);\n }\n });\n\n function releaseJoystick(event) {\n if (event.pointerId !== activePointerId) return;\n activePointerId = null;\n stopMotion();\n }\n\n joystick.addEventListener('pointerup', releaseJoystick);\n joystick.addEventListener('pointercancel', releaseJoystick);\n\n document.querySelectorAll('.pad-button').forEach(bindPadButton);\n\n [splitUi, roundUi].forEach((ui) => {\n ui.start.addEventListener('click', () => startConnection(ui));\n ui.stop.addEventListener('click', stopConnection);\n ui.speed.addEventListener('input', () => syncSpeed(ui.speed.value));\n ui.controller.addEventListener('change', () => {\n document.body.classList.add('controller-picked');\n setController(ui.controller.value);\n });\n });\n\n document.querySelectorAll('[data-controller]').forEach((button) => {\n button.addEventListener('click', () => {\n chooser.classList.remove('show');\n document.body.classList.add('controller-picked');\n setController(button.dataset.controller);\n });\n });\n\n fullscreenButton.addEventListener('click', async () => {\n try {\n if (!document.fullscreenElement) {\n await document.documentElement.requestFullscreen();\n fullscreenButton.textContent = 'Exit Full';\n } else {\n await document.exitFullscreen();\n fullscreenButton.textContent = 'Full Screen';\n }\n } catch (error) {\n fullscreenButton.textContent = 'Unavailable';\n }\n });\n\n document.addEventListener('fullscreenchange', () => {\n fullscreenButton.textContent = document.fullscreenElement ? 'Exit Full' : 'Full Screen';\n });\n\n window.addEventListener('resize', updateOrientationGate);\n\n syncSpeed(100);\n setConnected(false);\n setController('round');\n </script>\n</body>\n\n</html>\n");

